function getSafeLocalStorage(): Storage | null {
  if (typeof window === 'undefined') return null;
  try {
    return window.localStorage;
  } catch (_error) {
    return null;
  }
}

function normalizeUsername(value: string): string {
  return String(value || '').trim().toLowerCase();
